private getPodDeleteModes(pod: Pod): DeleteType[] {
  const hasDeletionTimestamp = !!pod.metadata.deletionTimestamp;
  const hasFinalizers = pod.getFinalizers().length > 0;
  const podPhase = pod.getStatusPhase();

  if (!hasDeletionTimestamp) {
    const skipForceDelete = podPhase === PodStatusPhase.SUCCEEDED || podPhase === PodStatusPhase.FAILED || podPhase === 'Unknown';
    if (skipForceDelete) {
      return ['delete'];
    } else {
      if ((pod.spec.terminationGracePeriodSeconds ?? 30) > 0) {
        return ['force_delete', 'delete'];
      } else {
        return ['delete'];
      }
    }
  } else {
    if (hasFinalizers) {
      return ['force_finalize'];
    }
    const skipForceDelete = podPhase === PodStatusPhase.SUCCEEDED || podPhase === PodStatusPhase.FAILED || podPhase === 'Unknown';
    if (skipForceDelete) {
      return ['delete'];
    } else {
      const hasRunningContainers = pod.getContainerStatuses?.().some((status) => status.state?.running || status.state?.waiting);
      if (hasRunningContainers || podPhase === PodStatusPhase.RUNNING) {
        return ['force_delete'];
      } else {
        return ['delete'];
      }
    }
  }
}

const execShell = async (container: Container | EphemeralContainer) => {
  const containerName = container.name;
  const kubectlPath = App.Preferences.getKubectlPath() || 'kubectl';
  const commandParts = [kubectlPath, 'exec', '-i', '-t', '-n', pod.getNs(), pod.getName()];

  if (os.platform() !== 'win32') {
    commandParts.unshift('exec');
  }

  if (containerName) {
    commandParts.push('-c', containerName);
  }

  commandParts.push('--');

  if (pod.getSelectedNodeOs() === 'windows') {
    commandParts.push('powershell');
  } else {
    commandParts.push('sh -c "clear; (bash || ash || sh)"');
  }

  const shellId = uuidv4();

  createTerminalTab({
    title: `Pod: ${pod.getName()} (namespace: ${pod.getNs()})`,
    id: shellId,
  });

  sendCommand(commandParts.join(' '), {
    enter: true,
    tabId: shellId,
  }).then(hideDetails);
};

